t.script:
//
document.addEventListener('DOMContentLoaded', function () {

    // =====================================================================
    // TABLES DE CORRESPONDANCE RÉDUCTIONS (miroir du modèle Python)
    // =====================================================================
    var CHILDREN_MAP = {1: 0.0, 2: 10.0, 3: 20.0, 4: 30.0};
    var SENIORITY_MAP = {'5': 0.0, '6': 2.0, '7': 4.0, '8': 6.0, '9': 8.0, '10': 10.0};

    // Nombre d'élèves existants côté serveur (utilisé pour le calcul enfants)
    var serverStudentCount = parseInt('<t t-out="len(dossier.student_line_ids)"/>') || 0;

    // =====================================================================
    // UTILITAIRES
    // =====================================================================
    function setVal(id, val) {
        var el = document.getElementById(id);
        if (el) el.value = (typeof val === 'number') ? val.toFixed(2) : val;
    }
    function setInner(id, val) {
        var el = document.getElementById(id);
        if (el) el.innerText = (typeof val === 'number') ? val.toFixed(2) : val;
    }
    function getCheckedVal(name) {
        var el = document.querySelector('input[name="' + name + '"]:checked');
        return el ? el.value : null;
    }

    // =====================================================================
    // REDIRECT APRÈS SAVE : on lit dossier_id depuis le champ hidden
    // Le contrôleur redirige déjà vers /my/ecolage?success=1
    // On surcharge la soumission pour rediriger vers /my/ecolage/edit/{id}
    // =====================================================================
    var dossierId = document.querySelector('input[name="dossier_id"]') ?
        document.querySelector('input[name="dossier_id"]').value : null;

    var mainForm = document.querySelector('form');


    // =====================================================================
    // REPRÉSENTANT LÉGAL
    // =====================================================================
    function initForm() {
        var radiosLegal = document.querySelectorAll('input[name="legal_representation"]');
        if (radiosLegal.length === 0) { setTimeout(initForm, 100); return; }

        function updateLegalVisibility() {
            var val = getCheckedVal('legal_representation');
            var p1 = document.getElementById('block_parent1');
            var p2 = document.getElementById('block_parent2');
            var other = document.getElementById('block_other');
            if (p1) p1.style.display = (val === 'both' || val === 'father_only') ? 'block' : 'none';
            if (p2) p2.style.display = (val === 'both' || val === 'mother_only') ? 'block' : 'none';
            if (other) other.style.display = (val === 'other') ? 'block' : 'none';
            updateCotisation();
        }
        radiosLegal.forEach(function(r) { r.addEventListener('change', updateLegalVisibility); });
        updateLegalVisibility();

        // ---- Même adresse parent 2 (masque adresse ET pays) ----
        var cbSameAddr = document.getElementById('same_address_as_parent1');
        var blockAddr2 = document.getElementById('block_parent2_address');
        var blockCountry2 = document.getElementById('block_parent2_country');
        if (cbSameAddr) {
            function toggleAddr2() {
                var hide = cbSameAddr.checked;
                if (blockAddr2) blockAddr2.style.display = hide ? 'none' : 'block';
                if (blockCountry2) blockCountry2.style.display = hide ? 'none' : 'block';
            }
            cbSameAddr.addEventListener('change', toggleAddr2);
            toggleAddr2();
        }

        // ---- Gestion élèves (ajout) ----
        var btnAdd = document.getElementById('btn_add_student');
        if (btnAdd) {
            btnAdd.addEventListener('click', function() {
                var template = document.querySelector('#new_student_template .card');
                if (!template) return;
                var clone = template.cloneNode(true);
                clone.querySelector('.btn-remove-new-student').addEventListener('click', function() {
                    clone.remove();
                    checkStudentInfoMsg();
                });
                document.getElementById('students_list').appendChild(clone);
                checkStudentInfoMsg();
            });
        }

 // =====================================================================
// Gestion élèves : suppression immédiate par AJAX (élèves existants)
// =====================================================================
var csrfToken = document.querySelector('input[name="csrf_token"]')?.value || '';

document.addEventListener('click', function(e) {
    var btn = e.target.closest('.btn-remove-student');
    if (!btn) return;
    e.preventDefault();

    var lineDiv = btn.closest('.student-line');
    var lineId = btn.getAttribute('data-line-id');
    if (!lineId) return;

    fetch('/my/ecolage/delete_student_line', {
        method: 'POST',
        headers: {
            'Content-Type': 'application/json',
            'X-CSRFToken': csrfToken
        },
        body: JSON.stringify({ line_id: lineId })
    })
    .then(response => response.json())
    .then(data => {
        var success = data.result ? data.result.success : (data.success || false);
        if (success) {
            // 1. Supprimer la ligne principale (élève)
            lineDiv.remove();

            // 2. Supprimer le bloc Forfait correspondant
            var forfaitDiv = document.querySelector(`.forfait-line[data-line-id="${lineId}"]`);
            if (forfaitDiv) forfaitDiv.remove();

            // 3. Supprimer la carte Parascolaire correspondante
            //    On cible la carte qui contient le toggle "after_school_selected_{lineId}"
            var afterCard = document.querySelector(`.card.mb-3.border:has(.after-school-toggle[name="after_school_selected_${lineId}"])`);
            if (afterCard) afterCard.remove();

            // 4. Recalculer tous les totaux
            if (typeof updateTotalMensuel === 'function') updateTotalMensuel();
            if (typeof updateAllDiscounts === 'function') updateAllDiscounts();
            if (typeof updateAfterSchoolTotal === 'function') updateAfterSchoolTotal();
            if (typeof updateRecapTotals === 'function') updateRecapTotals();
            if (typeof checkStudentInfoMsg === 'function') checkStudentInfoMsg();
        } else {
            var errorMsg = (data.result && data.result.error) || data.error || 'Impossible de supprimer';
            alert('Erreur : ' + errorMsg);
        }
    })
    .catch(error => {
        console.error('Erreur réseau:', error);
        alert('Erreur de connexion. Veuillez réessayer.');
    });
});

// =====================================================================
// Suppression d'un nouvel élève (jamais en base) : simple suppression DOM
// =====================================================================
document.addEventListener('click', function(e) {
    var btn = e.target.closest('.btn-remove-new-student');
    if (!btn) return;
    e.preventDefault();
    btn.closest('.student-line').remove();
    checkStudentInfoMsg();
});

// =====================================================================
// Fonction d'affichage du message d'info (modifiée car plus de champs hidden)
// =====================================================================
function checkStudentInfoMsg() {
    var infoDiv = document.getElementById('new_student_info');
    if (!infoDiv) return;
    var hasNew = document.querySelector('#students_list .new-student') !== null;
    // On affiche le message uniquement s'il y a des nouveaux élèves (non encore enregistrés)
    // Les suppressions sont immédiates, donc plus besoin de champ hidden
    infoDiv.style.display = hasNew ? 'block' : 'none';
}

        // ---- Aide employeur ----
        var employerRadios = document.querySelectorAll('input[name="employer_assistance"]');
        var blockEmployerYes = document.getElementById('block_employer_yes');
        function toggleEmployerYes() {
            if (!blockEmployerYes) return;
            blockEmployerYes.style.display = (getCheckedVal('employer_assistance') === 'yes') ? 'block' : 'none';
        }
        employerRadios.forEach(function(r) { r.addEventListener('change', toggleEmployerYes); });
        toggleEmployerYes();

        // ---- Envoyer facture à l'employeur ----
        var chkInvoice = document.getElementById('send_invoice_to_employer');
        var blockEmployerId = document.getElementById('block_employer_id');
        if (chkInvoice && blockEmployerId) {
            function toggleEmployerBlock() {
                blockEmployerId.style.display = chkInvoice.checked ? 'block' : 'none';
            }
            toggleEmployerBlock();
            chkInvoice.addEventListener('change', toggleEmployerBlock);
        }

        // ---- Textareas data-initial ----
        document.querySelectorAll('textarea[data-initial]').forEach(function(textarea) {
            var v = textarea.getAttribute('data-initial') || '';
            if (textarea.value !== v) textarea.value = v;
        });
    }

    // =====================================================================
    // FORFAITS & COTISATION
    // =====================================================================
    function updateForfaitMontant(selectEl, montantInput) {
        var selectedOption = selectEl.options[selectEl.selectedIndex];
        var montant = 0;
        if (selectedOption && selectedOption.value) {
            var text = selectedOption.text;
            var match = text.match(/(\d+(?:\.\d+)?)\s*CHF/);
            if (match) montant = parseFloat(match[1]);
        }
        montantInput.value = montant.toFixed(2);
        updateTotalMensuel();
        updateCotisation();
        updateAllDiscounts();
    }

    function updateTotalMensuel() {
        var total = 0;
        document.querySelectorAll('.montant-mensuel').forEach(function(input) {
            var val = parseFloat(input.value);
            if (!isNaN(val)) total += val;
        });
        setInner('total_monthly_fee', total);
        updateAllDiscounts();
    }

    function updateCotisation() {
        var val = getCheckedVal('legal_representation');
        var montant = 40;
        if (val === 'both') montant = 60;
        else if (val === 'other') montant = 0;
        setInner('membership_fee_amount', montant);
        updateRecapTotals();
    }

    function updateDepot() {
        var val = getCheckedVal('deposit_status');
        var montant = (val === 'unpaid') ? 1000 : 0;
        setInner('deposit_amount', montant);
        updateRecapTotals();
    }

    document.querySelectorAll('input[name="deposit_status"]').forEach(function(r) {
        r.addEventListener('change', updateDepot);
    });
    updateDepot();

    document.querySelectorAll('.forfait-select').forEach(function(select) {
        var lineId = select.getAttribute('data-line-id');
        var montantInput = document.querySelector('.montant-mensuel[data-line-id="' + lineId + '"]');
        if (montantInput) {
            select.addEventListener('change', function() { updateForfaitMontant(select, montantInput); });
            updateForfaitMontant(select, montantInput);
        }
    });

    document.querySelectorAll('input[name="legal_representation"]').forEach(function(r) {
        r.addEventListener('change', updateCotisation);
    });
    updateCotisation();

    // =====================================================================
    // CALCULS RÉDUCTIONS (100% JS, miroir du modèle Python)
    // =====================================================================

    function getBaseMensuel() {
        var total = 0;
        document.querySelectorAll('.montant-mensuel').forEach(function(input) {
            var val = parseFloat(input.value);
            if (!isNaN(val)) total += val;
        });
        return total;
    }

    function getAfterSchoolTotal() {
        var total = 0;
        document.querySelectorAll('.after-school-montant').forEach(function(input) {
            var optionsDiv = input.closest('.after-school-options');
            if (optionsDiv && optionsDiv.style.display !== 'none') {
                var val = parseFloat(input.value);
                if (!isNaN(val)) total += val;
            }
        });
        return total;
    }

    function getNbStudents() {
        // Compter les élèves existants visibles (non supprimés) + nouveaux ajoutés
        var existing = document.querySelectorAll('#students_list .student-line:not(.new-student)').length;
        // Retirer ceux marqués pour suppression
        var deleted = document.querySelectorAll('input[name^="delete_student_line_"]').length;
        var newAdded = document.querySelectorAll('#students_list .new-student').length;
        return Math.max(0, existing - deleted) + newAdded;
    }

    function updateAllDiscounts() {
        var reductionRequested = getCheckedVal('reduction_requested') === '1';
        var blockReduction = document.getElementById('block_reduction_yes');
        if (blockReduction) blockReduction.style.display = reductionRequested ? 'block' : 'none';

        if (!reductionRequested) {
            updateRecapTotals();
            return;
        }

        var nb = Math.min(getNbStudents(), 4);
        var maxChildrenDisc = CHILDREN_MAP[nb] || 0.0;

        var seniorityVal = document.getElementById('seniority_years') ?
            document.getElementById('seniority_years').value : '5';
        var maxSeniorityDisc = SENIORITY_MAP[seniorityVal] || 0.0;

        var applyChildren = document.getElementById('apply_children_discount') ?
            document.getElementById('apply_children_discount').checked : false;
        var applySeniority = document.getElementById('apply_seniority_discount') ?
            document.getElementById('apply_seniority_discount').checked : false;

        var childrenDisc = applyChildren ? maxChildrenDisc : 0.0;
        var seniorityDisc = applySeniority ? maxSeniorityDisc : 0.0;
        var maxTotalDisc = maxChildrenDisc + maxSeniorityDisc;

        var base = getBaseMensuel();

        var feeAfterChildren = base * (1 - childrenDisc / 100.0);
        var feeAfterSeniority = base * (1 - seniorityDisc / 100.0);
        var feeAtMax = base * (1 - maxTotalDisc / 100.0);

        // Affichage
        setVal('max_children_discount_display', maxChildrenDisc);
        setVal('monthly_fee_after_children_display', feeAfterChildren);
        setVal('max_seniority_discount_display', maxSeniorityDisc);
        setVal('monthly_fee_after_seniority_display', feeAfterSeniority);
        setVal('max_total_discount_display', maxTotalDisc);
        setVal('monthly_fee_at_max_display', feeAtMax);

        // Réduction moindre
        var reductionMoindre = getCheckedVal('reduction_moindre') === '1';
        var blockMoindre = document.getElementById('block_reduction_moindre');
        if (blockMoindre) blockMoindre.style.display = reductionMoindre ? 'block' : 'none';

        var requestedDisc = 0.0;
        if (reductionMoindre) {
            var rdInput = document.getElementById('requested_discount');
            if (rdInput) {
                requestedDisc = Math.min(parseFloat(rdInput.value) || 0, maxTotalDisc);
            }
        } else {
            requestedDisc = maxTotalDisc;
        }

        // Si réduction moindre non activée → on applique le max
        var feeAfterRequested = base * (1 - requestedDisc / 100.0);
        setVal('monthly_fee_after_requested_display', feeAfterRequested);

        // Calcul pourcentage revenu brut (depuis feeAtMax)
        updateIncomePercentage(feeAtMax);

        updateRecapTotals();
        updateSolidarityTotal();
    }

    function updateIncomePercentage(feeAtMax) {
        var grossIncome = parseFloat(document.getElementById('gross_annual_income') ?
            document.getElementById('gross_annual_income').value : 0) || 0;
        var incomeEl = document.getElementById('income_percentage_display');
        if (!incomeEl) return;
        if (grossIncome > 0 && feeAtMax > 0) {
            var annualFee = feeAtMax * 12;
            incomeEl.value = ((annualFee / grossIncome) * 100).toFixed(2);
        } else {
            incomeEl.value = '0.00';
        }
    }

    // Écouteurs réductions
    document.querySelectorAll('input[name="reduction_requested"]').forEach(function(r) {
        r.addEventListener('change', updateAllDiscounts);
    });
    var senioritySelect = document.getElementById('seniority_years');
    if (senioritySelect) senioritySelect.addEventListener('change', updateAllDiscounts);
    var applyChildrenCb = document.getElementById('apply_children_discount');
    if (applyChildrenCb) applyChildrenCb.addEventListener('change', updateAllDiscounts);
    var applySeniorityCb = document.getElementById('apply_seniority_discount');
    if (applySeniorityCb) applySeniorityCb.addEventListener('change', updateAllDiscounts);
    document.querySelectorAll('input[name="reduction_moindre"]').forEach(function(r) {
        r.addEventListener('change', updateAllDiscounts);
    });
    var rdInput = document.getElementById('requested_discount');
if (rdInput) {
    rdInput.addEventListener('input', function() {
        var maxEl = document.getElementById('max_total_discount_display');
        var max = parseFloat(maxEl ? maxEl.value : 0) || 0;
        var val = parseFloat(rdInput.value) || 0;
        if (val > max) {
            rdInput.value = max;
            rdInput.classList.add('is-invalid');
            var feedback = document.getElementById('requested_discount_feedback');
            if (!feedback) {
                feedback = document.createElement('div');
                feedback.id = 'requested_discount_feedback';
                feedback.className = 'invalid-feedback';
                feedback.innerText = 'La réduction ne peut pas dépasser ' + max.toFixed(1) + '%.';
                rdInput.parentNode.appendChild(feedback);
            }
            feedback.innerText = 'La réduction ne peut pas dépasser ' + max.toFixed(1) + '%.';
        } else {
            rdInput.classList.remove('is-invalid');
            var feedback = document.getElementById('requested_discount_feedback');
            if (feedback) feedback.style.display = 'none';
        }
        updateAllDiscounts();
    });
}

    var grossIncomeInput = document.getElementById('gross_annual_income');
    if (grossIncomeInput) grossIncomeInput.addEventListener('input', updateAllDiscounts);

    // Initialisation état bouton réduction moindre
    // (si requested_discount < max → cocher "oui", sinon "non")
    (function initReductionMoindre() {
        var rdVal = parseFloat((document.getElementById('requested_discount') || {}).value) || 0;
        // On laisse l'utilisateur choisir, par défaut Non sélectionné
        var radioNon = document.getElementById('reduction_moindre_non');
        if (radioNon) radioNon.checked = true;
    })();

    // =====================================================================
    // RÉDUCTION COMPLÉMENTAIRE — masquage si réduction moindre = oui
    // =====================================================================
    function toggleAdditionalReductionVisibility() {
        var reductionMoindre = getCheckedVal('reduction_moindre') === '1';
        var blockQ = document.getElementById('block_reduction_complementaire_question');
        var blockContent = document.getElementById('block_additional_reduction');
        // Si réduction moindre activée, masquer la question ET le bloc réduction complémentaire
        if (reductionMoindre) {
            if (blockQ) blockQ.style.display = 'none';
            if (blockContent) blockContent.style.display = 'none';
        } else {
            if (blockQ) blockQ.style.display = 'block';
            // Laisser block_additional_reduction géré par son propre radio
            toggleAdditionalReduction();
        }
    }
    document.querySelectorAll('input[name="reduction_moindre"]').forEach(function(r) {
        r.addEventListener('change', function() {
            updateAllDiscounts();
            toggleAdditionalReductionVisibility();
        });
    });

    function toggleAdditionalReduction() {
        var checked = getCheckedVal('additional_reduction_request');
        var block = document.getElementById('block_additional_reduction');
        if (block) block.style.display = (checked === '1') ? 'block' : 'none';
    }
    document.querySelectorAll('input[name="additional_reduction_request"]').forEach(function(r) {
        r.addEventListener('change', toggleAdditionalReduction);
    });
    toggleAdditionalReduction();
    toggleAdditionalReductionVisibility();

    // =====================================================================
    // LETTRE EXPLICATIVE
    // =====================================================================
    function toggleExplanatoryLetter() {
        var checked = getCheckedVal('explanatory_letter_mode');
        var blockUpload = document.getElementById('block_letter_upload');
        var blockWrite = document.getElementById('block_letter_write');
        if (!blockUpload || !blockWrite) return;
        var isWrite = (checked === 'write');
        blockUpload.style.display = isWrite ? 'none' : 'block';
        blockWrite.style.display = isWrite ? 'block' : 'none';
    }
    document.querySelectorAll('input[name="explanatory_letter_mode"]').forEach(function(r) {
        r.addEventListener('change', toggleExplanatoryLetter);
    });
    toggleExplanatoryLetter();

    // =====================================================================
    // BUDGET (upload / online)
    // =====================================================================
    function toggleBudgetMethod() {
        var checked = getCheckedVal('budget_method');
        var blockUpload = document.getElementById('block_budget_upload');
        var blockOnline = document.getElementById('block_budget_online');
        if (!blockUpload || !blockOnline) return;
        var isOnline = (checked === 'online');
        blockUpload.style.display = isOnline ? 'none' : 'block';
        blockOnline.style.display = isOnline ? 'block' : 'none';
    }
    document.querySelectorAll('input[name="budget_method"]').forEach(function(r) {
        r.addEventListener('change', toggleBudgetMethod);
    });
    toggleBudgetMethod();

    // =====================================================================
    // CALCUL BUDGET EN LIGNE
    // =====================================================================
    (function() {
    function updateBudgetTotals() {
        var revenusMadame = 0, revenusMonsieur = 0;
        var chargesMadame = 0, chargesMonsieur = 0;

        // Revenus
        var revenusHeader = document.querySelector('#block_budget_online .text-success');
        if (revenusHeader) {
            var tbody = revenusHeader.closest('.mb-4').querySelector('table tbody');
            if (tbody) {
                tbody.querySelectorAll('tr').forEach(function(row) {
                    // Ignorer la ligne "Salaire net (à titre indicatif)"
                    var categoryCell = row.querySelector('td:first-child');
                    if (categoryCell) {
                        var categoryName = categoryCell.innerText.trim();
                        var categoriesToIgnore = ['Salaire net (à titre indicatif)', 'Fortune (immobilière, etc)'];
        if (categoriesToIgnore.includes(categoryName)) return;
    }
                    var madame = row.querySelector('input[name^="montant_madame_"]');
                    var monsieur = row.querySelector('input[name^="montant_monsieur_"]');
                    if (madame && monsieur) {
                        revenusMadame += parseFloat(madame.value) || 0;
                        revenusMonsieur += parseFloat(monsieur.value) || 0;
                    }
                });
            }
        }

        // Charges (identique, si besoin d'ignorer certaines lignes)
        var chargesHeader = document.querySelector('#block_budget_online .text-danger');
        if (chargesHeader) {
            var tbody2 = chargesHeader.closest('.mb-4').querySelector('table tbody');
            if (tbody2) {
                tbody2.querySelectorAll('tr').forEach(function(row) {
                    var madame = row.querySelector('input[name^="montant_madame_"]');
                    var monsieur = row.querySelector('input[name^="montant_monsieur_"]');
                    if (madame && monsieur) {
                        chargesMadame += parseFloat(madame.value) || 0;
                        chargesMonsieur += parseFloat(monsieur.value) || 0;
                    }
                });
            }
        }

        var totalRevenus = revenusMadame + revenusMonsieur;
        var totalCharges = chargesMadame + chargesMonsieur;
        var solde = totalRevenus - totalCharges;
        function setSpan(id, val) { var el = document.getElementById(id); if (el) el.innerText = val.toFixed(2); }
        setSpan('total_revenus_madame_span', revenusMadame);
        setSpan('total_revenus_monsieur_span', revenusMonsieur);
        setSpan('total_revenus_span', totalRevenus);
        setSpan('total_charges_madame_span', chargesMadame);
        setSpan('total_charges_monsieur_span', chargesMonsieur);
        setSpan('total_charges_span', totalCharges);
        setSpan('solde_span', solde);
    }

    function attachBudgetEvents() {
        var inputs = document.querySelectorAll('#block_budget_online input[type="number"]');
        inputs.forEach(function(input) { input.addEventListener('input', updateBudgetTotals); });
        updateBudgetTotals();
    }
    var checkInterval = setInterval(function() {
        if (document.getElementById('block_budget_online')) {
            clearInterval(checkInterval);
            attachBudgetEvents();
        }
    }, 100);
})();

    // =====================================================================
    // PARASCOLAIRE
    // =====================================================================
    function updateAfterSchoolTotal() {
        var total = 0;
        document.querySelectorAll('.after-school-montant').forEach(function(input) {
            var optionsDiv = input.closest('.after-school-options');
            if (optionsDiv && optionsDiv.style.display !== 'none') {
                var val = parseFloat(input.value);
                if (!isNaN(val)) total += val;
            }
        });
        setInner('after_school_total_amount', total);
        updateRecapTotals();
    }

    function setMontant(studentLineId, montant) {
        var montantInput = document.querySelector('.after-school-montant[data-student-line-id="' + studentLineId + '"]');
        if (montantInput) montantInput.value = montant.toFixed(2);
    }

    function updateAfterSchoolMontant(studentLineId) {
        var optionsDiv = document.querySelector('.after-school-options[data-student-line-id="' + studentLineId + '"]');
        if (!optionsDiv) return;
        var selectedRadio = optionsDiv.querySelector('input[name^="accueil_type_"]:checked');
        if (!selectedRadio) { setMontant(studentLineId, 0); updateAfterSchoolTotal(); return; }
        var accueilValue = selectedRadio.value;
        var useJardinPrix = (accueilValue === 'jardin' || accueilValue === 'jardins_enfants');
        var total = 0;
        optionsDiv.querySelectorAll('.prestation-checkbox:checked').forEach(function(cb) {
            var prix = useJardinPrix ? cb.getAttribute('data-prix-jardin') : cb.getAttribute('data-prix-classe');
            var val = parseFloat(prix);
            if (!isNaN(val)) total += val;
        });
        setMontant(studentLineId, total);
        updateAfterSchoolTotal();
    }

    function filterPrestationsByAccueilType(optionsDiv) {
        var selectedRadio = optionsDiv.querySelector('input[name^="accueil_type_"]:checked');
        var prestationItems = optionsDiv.querySelectorAll('.prestation-item');
        if (!selectedRadio) {
            prestationItems.forEach(function(prestaDiv) {
                prestaDiv.style.display = 'none';
                var checkbox = prestaDiv.querySelector('input[type="checkbox"]');
                if (checkbox && checkbox.checked) checkbox.checked = false;
            });
            return;
        }
        var accueilValue = selectedRadio.value;
        prestationItems.forEach(function(prestaDiv) {
            var applicable = (prestaDiv.getAttribute('data-applicable') || 'both').toLowerCase().trim();
            var isBoth = (applicable === 'both' || applicable === '' || applicable === 'false');
            var visible = isBoth || (applicable === accueilValue);
            prestaDiv.style.display = visible ? '' : 'none';
            if (!visible) {
                var checkbox = prestaDiv.querySelector('input[type="checkbox"]');
                if (checkbox && checkbox.checked) { checkbox.checked = false; }
            }
        });
    }

    function initAfterSchoolForStudent(studentLineId) {
        var optionsDiv = document.querySelector('.after-school-options[data-student-line-id="' + studentLineId + '"]');
        if (!optionsDiv) return;
        optionsDiv.querySelectorAll('input[name^="accueil_type_' + studentLineId + '"]').forEach(function(radio) {
            radio.addEventListener('change', function() {
                filterPrestationsByAccueilType(optionsDiv);
                updateAfterSchoolMontant(studentLineId);
            });
        });
        optionsDiv.querySelectorAll('.prestation-checkbox').forEach(function(cb) {
            cb.addEventListener('change', function() { updateAfterSchoolMontant(studentLineId); });
        });
        filterPrestationsByAccueilType(optionsDiv);
        updateAfterSchoolMontant(studentLineId);
    }

    function initAfterSchoolOptions() {
        document.querySelectorAll('.after-school-toggle').forEach(function(cb) {
            function toggle() {
                var optionsDiv = cb.closest('.card-body').querySelector('.after-school-options');
                if (optionsDiv) { optionsDiv.style.display = cb.checked ? 'block' : 'none'; updateAfterSchoolTotal(); }
            }
            cb.removeEventListener('change', toggle);
            cb.addEventListener('change', toggle);
            toggle();
        });
        document.querySelectorAll('.after-school-options').forEach(function(optionsDiv) {
            var studentLineId = optionsDiv.getAttribute('data-student-line-id');
            if (!studentLineId) {
                var radio = optionsDiv.querySelector('input[name^="accueil_type_"]');
                if (radio) { var match = radio.name.match(/accueil_type_(\d+)/); if (match) studentLineId = match[1]; }
            }
            if (studentLineId) { optionsDiv.setAttribute('data-student-line-id', studentLineId); initAfterSchoolForStudent(studentLineId); }
        });
        updateAfterSchoolTotal();
    }

    function toggleAfterSchool() {
    var block = document.getElementById('block_after_school_yes');
    var isYes = (getCheckedVal('after_school_request') === 'yes');
    if (block) {
        block.style.display = isYes ? 'block' : 'none';
    }
    if (!isYes) {
        // Désinscrire tous les élèves : décocher les toggles et réinitialiser les options
        document.querySelectorAll('.after-school-toggle').forEach(function(toggle) {
            if (toggle.checked) {
                toggle.checked = false;
                // Déclencher l'événement change pour que l'affichage des options se mette à jour
                var event = new Event('change', { bubbles: true });
                toggle.dispatchEvent(event);
            }
        });
        // Recalculer les totaux (ils passeront à 0)
        updateAfterSchoolTotal();
        updateRecapTotals();
    } else {
        // Si on revient à "Oui", rien de spécial : les toggles sont déjà décochés
        updateAfterSchoolTotal();
        updateRecapTotals();
    }
}
    document.querySelectorAll('input[name="after_school_request"]').forEach(function(r) { r.addEventListener('change', toggleAfterSchool); });
    toggleAfterSchool();
    initAfterSchoolOptions();

    // Parrainage
document.querySelectorAll('input[name="sponsorship_request"]').forEach(function(r) {
    r.addEventListener('change', function() {
        var block = document.getElementById('block_sponsorship_yes');
        if (block) block.style.display = (getCheckedVal('sponsorship_request') === 'yes') ? 'block' : 'none';
    });
});

var btnAddSp = document.getElementById('btn_add_sponsorship');
if (btnAddSp) {
    btnAddSp.addEventListener('click', function() {
        var template = document.querySelector('#new_sponsorship_template .card');
        if (!template) return;
        var clone = template.cloneNode(true);
        clone.querySelector('.btn-remove-new-sponsorship').addEventListener('click', function() {
            clone.remove();
        });
        document.getElementById('sponsorship_list').appendChild(clone);
    });
}

document.addEventListener('click', function(e) {
    var btn = e.target.closest('.btn-remove-sponsorship');
    if (!btn) return;
    btn.closest('.sponsorship-item').remove();
});

    // =====================================================================
    // SOLIDARITÉ
    // =====================================================================
    function updateSolidarityTotal() {
        var solidarityYes = getCheckedVal('solidarity_request') === 'yes';
        var blockSolidarity = document.getElementById('block_solidarity_yes');
        if (blockSolidarity) blockSolidarity.style.display = solidarityYes ? 'block' : 'none';

        var applyIncrease = document.getElementById('apply_solidarity_increase');
        var percentInput = document.getElementById('solidarity_percentage');
        var totalField = document.getElementById('solidarity_total_amount');
        if (!totalField) return;

        var ecolageMonthly = getEcolageBeforeSolidarity();
var base = ecolageMonthly;

        var isChecked = applyIncrease && applyIncrease.checked;
        var percent = percentInput ? (parseFloat(percentInput.value) || 0) : 0;
        var total = (isChecked && percent > 0) ? base * (1 + percent / 100) : 0;
        totalField.value = total.toFixed(2);
    }
function getEcolageBeforeSolidarity() {
    var reductionRequested = getCheckedVal('reduction_requested') === '1';
    if (!reductionRequested) {
        return getBaseMensuel();
    }
    var el = document.getElementById('monthly_fee_after_requested_display');
    return el ? (parseFloat(el.value) || 0) : getBaseMensuel();
}
    function getEcolageAfterDiscount() {
    var base = getEcolageBeforeSolidarity();
    var solidarityYes = getCheckedVal('solidarity_request') === 'yes';
    var applyIncrease = document.getElementById('apply_solidarity_increase');
    var percentInput = document.getElementById('solidarity_percentage');
    if (solidarityYes && applyIncrease && applyIncrease.checked && percentInput) {
        var percent = parseFloat(percentInput.value) || 0;
        if (percent > 0) {
            base = base * (1 + percent / 100);
        }
    }
    return base;
}

    document.querySelectorAll('input[name="solidarity_request"]').forEach(function(r) { r.addEventListener('change', function() { updateSolidarityTotal(); updateRecapTotals(); }); });
    var chkApply = document.getElementById('apply_solidarity_increase');
    if (chkApply) chkApply.addEventListener('change', function() { updateSolidarityTotal(); updateRecapTotals(); });
    var percentInput = document.getElementById('solidarity_percentage');
    if (percentInput) percentInput.addEventListener('input', function() { updateSolidarityTotal(); updateRecapTotals(); });

    // =====================================================================
    // RÉCAPITULATIFS
    // =====================================================================
    function updateRecapTotals() {
    var ecolageMonthly = getEcolageAfterDiscount();
    var afterMonthly = getAfterSchoolTotal();
    var totalMonthly = ecolageMonthly + afterMonthly;
    var annualTuition = ecolageMonthly * 12;
    var annualAfter = afterMonthly * 12;
    var membership = parseFloat((document.getElementById('membership_fee_amount') || {}).innerText) || 0;
    var deposit = parseFloat((document.getElementById('deposit_amount') || {}).innerText) || 0;
    var totalAnnual = annualTuition + annualAfter + membership + deposit;

    setVal('recap_monthly_tuition', ecolageMonthly);
    setVal('recap_monthly_after_school', afterMonthly);
    setVal('recap_total_monthly', totalMonthly);
    setVal('recap_annual_tuition', annualTuition);
    setVal('recap_annual_after_school', annualAfter);
    setVal('recap_annual_membership', membership);
    setVal('recap_deposit', deposit);
    setVal('recap_total_annual', totalAnnual);   // total sans réduction

    // Gestion du bloc réduction 2% sur le total annuel complet
    var paymentTerms = getCheckedVal('payment_terms');
    var additionalReduction = getCheckedVal('additional_reduction_request');
    var discountApplicable = (paymentTerms === 'annually' && additionalReduction !== '1');
    var discountBlock = document.getElementById('total_with_discount_block');
    var discountedInput = document.getElementById('recap_total_annual_discounted');
    if (discountApplicable) {
        var totalWithDiscount = totalAnnual * 0.98;   // réduction sur le total complet
        if (discountBlock) discountBlock.style.display = 'block';
        if (discountedInput) discountedInput.value = totalWithDiscount.toFixed(2);
    } else {
        if (discountBlock) discountBlock.style.display = 'none';
    }
}
// Recalculer quand on change le mode de paiement ou la réduction complémentaire
document.querySelectorAll('input[name="payment_terms"]').forEach(function(radio) {
    radio.addEventListener('change', function() { updateRecapTotals(); });
});
document.querySelectorAll('input[name="additional_reduction_request"]').forEach(function(radio) {
    radio.addEventListener('change', function() { updateRecapTotals(); });
});
    // =====================================================================
    // BOUTONS ÉLÈVES
    // =====================================================================
    var addStudentBtn = document.getElementById('btn_add_student');
    if (addStudentBtn) {
        addStudentBtn.addEventListener('click', function() {
            var infoDiv = document.getElementById('new_student_info');
            if (infoDiv) infoDiv.style.display = 'block';
        });
    }

   //===========
   // division facture
   //===========
       (function() {
        var radioYes = document.getElementById('multi_yes');
        var radioNo = document.getElementById('multi_no');
        var container = document.getElementById('billing_amounts_container');
        var input1 = document.getElementById('parent1_billing_amount');
        var input2 = document.getElementById('parent2_billing_amount');

        function toggleAmounts() {
            if (radioYes && radioYes.checked) {
                container.style.display = 'flex';   // ou 'block' selon votre layout
                if (input1) input1.required = true;
                if (input2) input2.required = true;
            } else {
                container.style.display = 'none';
                if (input1) input1.required = false;
                if (input2) input2.required = false;
            }
        }

        if (radioYes && radioNo) {
            radioYes.addEventListener('change', toggleAmounts);
            radioNo.addEventListener('change', toggleAmounts);
            toggleAmounts(); // exécution au chargement
        }
    })();



    // =====================================================================
    // INITIALISATION GLOBALE
    // =====================================================================
    initForm();
    updateAllDiscounts();
    updateRecapTotals();
    updateSolidarityTotal();
});
